 1→import { useMemo } from "react";
 2→import type { DisplayMessage, SessionMeta, SessionTotals, GitInfo } from "../types";
 3→import { shortPath, shortMode, contextPercent, formatTokens, formatCost } from "../lib/format";
 4→import { getContextColor } from "../lib/theme";
 5→import { TokensIcon, CostIcon } from "./Icons";
 6→
 7→interface InfoBarProps {
 8→  meta: SessionMeta;
 9→  gitInfo: GitInfo | null;
10→  messages: DisplayMessage[];
11→  sessionTotals: SessionTotals;
12→  sessionPath: string;
13→  ongoing: boolean;
14→}
15→
16→export function InfoBar({
17→  meta,
18→  gitInfo,
19→  messages,
20→  sessionTotals,
21→  sessionPath,
22→  ongoing,
23→}: InfoBarProps) {
24→  const projectName = shortPath(meta.cwd);
25→  const sessionId = sessionPath.split("/").pop()?.replace(".jsonl", "") || "";
26→  const branch = gitInfo?.branch || meta.git_branch;
27→  const dirty = gitInfo?.dirty ?? false;
28→  const mode = meta.permission_mode;
29→  const ctxPct = useMemo(() => contextPercent(messages), [messages]);
30→
31→  const totalCost = sessionTotals.cost_usd;
32→
33→  const pillClass =
34→    mode === "bypassPermissions"
35→      ? "info-bar__pill--bypass"
36→      : mode === "acceptEdits"
37→        ? "info-bar__pill--acceptEdits"
38→        : mode === "plan"
39→          ? "info-bar__pill--plan"
40→          : "info-bar__pill--default";
41→
42→  return (
43→    <div className="info-bar">
44→      {projectName && <span className="info-bar__project">{projectName}</span>}
45→
46→      {sessionId && <span className="info-bar__session-id">{sessionId}</span>}
47→
48→      {branch && (
49→        <span className={`info-bar__branch${dirty ? " info-bar__branch--dirty" : ""}`}>
50→          {branch}
51→        </span>
52→      )}
53→
54→      {mode && mode !== "default" && (
55→        <span className={`info-bar__pill ${pillClass}`}>{shortMode(mode)}</span>
56→      )}
57→
58→      {ctxPct >= 0 && (
59→        <div className="info-bar__context">
60→          <span>ctx {ctxPct}%</span>
61→          <div className="info-bar__context-bar">
62→            <div
63→              className="info-bar__context-fill"
64→              style={{
65→                width: `${ctxPct}%`,
66→                backgroundColor: getContextColor(ctxPct),
67→              }}
68→            />
69→          </div>
70→        </div>
71→      )}
72→
73→      {sessionTotals.total_tokens > 0 && (
74→        <span className="info-bar__tokens">
75→          <TokensIcon /> {formatTokens(sessionTotals.total_tokens)} tok
76→        </span>
77→      )}
78→      {totalCost > 0 && (
79→        <span className="info-bar__cost">
80→          <CostIcon /> {formatCost(totalCost)}
81→        </span>
82→      )}
83→
84→      {ongoing && (
85→        <span className="info-bar__ongoing">
86→          <span className="braille-spinner" /> active
87→        </span>
88→      )}
89→    </div>
90→  );
91→}
