  1→import { useMemo } from "react";
  2→import { Box, Text } from "ink";
  3→import type { DisplayMessage, SessionMeta, SessionTotals } from "../api.js";
  4→import { formatTokens, formatCost } from "../lib/format.js";
  5→import { colors, getContextColor } from "../lib/theme.js";
  6→import { BrailleSpinner } from "./OngoingDots.js";
  7→import { IconBranch } from "../lib/icons.js";
  8→
  9→interface InfoBarProps {
 10→  meta: SessionMeta;
 11→  messages: DisplayMessage[];
 12→  sessionTotals: SessionTotals;
 13→  sessionPath: string;
 14→  ongoing: boolean;
 15→}
 16→
 17→function shortPath(cwd: string): string {
 18→  if (!cwd) return "";
 19→  const parts = cwd.split("/").filter(Boolean);
 20→  return parts[parts.length - 1] ?? cwd;
 21→}
 22→
 23→function shortMode(mode: string): string {
 24→  switch (mode) {
 25→    case "acceptEdits":
 26→      return "auto-edit";
 27→    case "bypassPermissions":
 28→      return "yolo";
 29→    case "plan":
 30→      return "plan";
 31→    default:
 32→      return mode;
 33→  }
 34→}
 35→
 36→function contextPercent(msgs: DisplayMessage[]): number {
 37→  const contextWindowSize = 1_000_000;
 38→  for (let i = msgs.length - 1; i >= 0; i--) {
 39→    if (msgs[i].role === "claude" && msgs[i].context_tokens > 0) {
 40→      return Math.min(Math.floor((msgs[i].context_tokens * 100) / contextWindowSize), 100);
 41→    }
 42→  }
 43→  return -1;
 44→}
 45→
 46→function modeColor(mode: string): string {
 47→  switch (mode) {
 48→    case "bypassPermissions":
 49→      return colors.pillBypass;
 50→    case "acceptEdits":
 51→      return colors.pillAcceptEdits;
 52→    case "plan":
 53→      return colors.pillPlan;
 54→    default:
 55→      return colors.textPrimary;
 56→  }
 57→}
 58→
 59→/** Middle dot separator — matches Go TUI's spaceBetween pattern. */
 60→function Dot() {
 61→  return <Text color={colors.textMuted}> · </Text>;
 62→}
 63→
 64→export function InfoBar({ meta, messages, sessionTotals, sessionPath, ongoing }: InfoBarProps) {
 65→  const projectName = shortPath(meta.cwd);
 66→  const sessionId = sessionPath.split("/").pop()?.replace(".jsonl", "") || "";
 67→  const branch = meta.git_branch;
 68→  const mode = meta.permission_mode;
 69→  const ctxPct = useMemo(() => contextPercent(messages), [messages]);
 70→
 71→  return (
 72→    <Box paddingX={2} borderStyle="round" borderColor={colors.border}>
 73→      {/* Left: path · branch · mode — Go TUI layout */}
 74→      <Box>
 75→        {projectName ? (
 76→          <Text bold color={colors.accent}>
 77→            {projectName}
 78→          </Text>
 79→        ) : null}
 80→        {sessionId ? (
 81→          <>
 82→            <Dot />
 83→            <Text color={colors.textDim}>{sessionId.slice(0, 8)}</Text>
 84→          </>
 85→        ) : null}
 86→        {branch ? (
 87→          <>
 88→            <Dot />
 89→            <Text color={colors.gitBranch}>
 90→              {IconBranch} {branch}
 91→            </Text>
 92→          </>
 93→        ) : null}
 94→        {mode && mode !== "default" ? (
 95→          <>
 96→            <Dot />
 97→            <Text color={modeColor(mode)} bold>
 98→              {shortMode(mode)}
 99→            </Text>
100→          </>
101→        ) : null}
102→      </Box>
103→
104→      {/* Spacer */}
105→      <Box flexGrow={1} />
106→
107→      {/* Right: ctx% · tokens · cost · ongoing */}
108→      <Box>
109→        {ctxPct >= 0 ? <Text color={getContextColor(ctxPct)}>ctx {ctxPct}%</Text> : null}
110→        {sessionTotals.total_tokens > 0 ? (
111→          <>
112→            <Dot />
113→            <Text color={colors.textDim}>{formatTokens(sessionTotals.total_tokens)} tok</Text>
114→          </>
115→        ) : null}
116→        {sessionTotals.cost_usd > 0 ? (
117→          <>
118→            <Dot />
119→            <Text color={colors.tokenHigh}>{formatCost(sessionTotals.cost_usd)}</Text>
120→          </>
121→        ) : null}
122→        {ongoing ? (
123→          <Box marginLeft={1}>
124→            <BrailleSpinner />
125→          </Box>
126→        ) : null}
127→      </Box>
128→    </Box>
129→  );
130→}
