  1→import { useMemo } from "react";
  2→import { Box, Text } from "ink";
  3→import { Spinner } from "@inkjs/ui";
  4→import type { SessionInfo } from "../api.js";
  5→import {
  6→  formatTokens,
  7→  formatCost,
  8→  timeAgo,
  9→  truncate,
 10→  shortModel,
 11→  modelColor,
 12→} from "../lib/format.js";
 13→import { OngoingDot } from "./OngoingDots.js";
 14→import { colors } from "../lib/theme.js";
 15→import { stableWindow } from "../lib/window.js";
 16→import {
 17→  IconSelected2,
 18→  IconBranch,
 19→  IconChat,
 20→  IconClock,
 21→  IconToken,
 22→  IconSession,
 23→  IconHRule,
 24→} from "../lib/icons.js";
 25→
 26→interface SessionPickerProps {
 27→  sessions: SessionInfo[];
 28→  loading: boolean;
 29→  error: string;
 30→  selectedIndex: number;
 31→}
 32→
 33→interface DateGroup {
 34→  category: string;
 35→  items: SessionInfo[];
 36→}
 37→
 38→function groupByDate(items: SessionInfo[]): DateGroup[] {
 39→  const now = new Date();
 40→  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
 41→  const yesterdayStart = new Date(todayStart.getTime() - 86400000);
 42→  const weekStart = new Date(todayStart.getTime() - 7 * 86400000);
 43→  const monthStart = new Date(todayStart.getTime() - 30 * 86400000);
 44→
 45→  const groups: Record<string, SessionInfo[]> = {};
 46→  const order = ["Today", "Yesterday", "This Week", "This Month", "Older"];
 47→
 48→  for (const item of items) {
 49→    const d = new Date(item.mod_time);
 50→    let cat: string;
 51→    if (d >= todayStart) cat = "Today";
 52→    else if (d >= yesterdayStart) cat = "Yesterday";
 53→    else if (d >= weekStart) cat = "This Week";
 54→    else if (d >= monthStart) cat = "This Month";
 55→    else cat = "Older";
 56→    (groups[cat] ??= []).push(item);
 57→  }
 58→
 59→  for (const cat of order) {
 60→    if (groups[cat]) {
 61→      groups[cat].sort((a, b) => new Date(b.mod_time).getTime() - new Date(a.mod_time).getTime());
 62→    }
 63→  }
 64→
 65→  return order
 66→    .filter((cat) => groups[cat]?.length)
 67→    .map((category) => ({ category, items: groups[category] }));
 68→}
 69→
 70→export function SessionPicker({ sessions, loading, error, selectedIndex }: SessionPickerProps) {
 71→  const dateGroups = useMemo(() => groupByDate(sessions), [sessions]);
 72→
 73→  const totalTokens = useMemo(
 74→    () => sessions.reduce((sum, s) => sum + s.total_tokens, 0),
 75→    [sessions],
 76→  );
 77→  const totalCost = useMemo(() => sessions.reduce((sum, s) => sum + s.cost_usd, 0), [sessions]);
 78→
 79→  if (loading) {
 80→    return (
 81→      <Box padding={1}>
 82→        <Spinner label="Discovering sessions..." />
 83→      </Box>
 84→    );
 85→  }
 86→
 87→  if (error) {
 88→    return (
 89→      <Box padding={1}>
 90→        <Text color={colors.error}>{error}</Text>
 91→      </Box>
 92→    );
 93→  }
 94→
 95→  // 3 lines per session card (message + metadata + separator) + date headers
 96→  const rows = process.stdout.rows || 24;
 97→  const windowSize = Math.max(3, Math.floor((rows - 6) / 3));
 98→  const { start, end } = stableWindow("picker", selectedIndex, sessions.length, windowSize);
 99→
100→  let flatIdx = 0;
101→  const cols = process.stdout.columns || 80;
102→
103→  return (
104→    <Box flexDirection="column">
105→      {/* Header bar */}
106→      <Box paddingX={1} gap={2} borderStyle="round" borderColor={colors.border}>
107→        <Text bold>Sessions ({sessions.length})</Text>
108→        {totalTokens > 0 && <Text dimColor>{formatTokens(totalTokens)} tok</Text>}
109→        {totalCost > 0 && <Text color={colors.tokenHigh}>{formatCost(totalCost)}</Text>}
110→      </Box>
111→
112→      {/* Session cards grouped by date */}
113→      {dateGroups.map((group) => {
114→        const groupItems = group.items.map((s) => {
115→          const idx = flatIdx++;
116→          return { session: s, idx };
117→        });
118→
119→        const firstInGroup = groupItems[0]?.idx ?? 0;
120→        const lastInGroup = groupItems[groupItems.length - 1]?.idx ?? 0;
121→        if (lastInGroup < start || firstInGroup >= end) return null;
122→
123→        return (
124→          <Box key={group.category} flexDirection="column">
125→            {firstInGroup >= start && firstInGroup < end && (
126→              <Box paddingX={1} marginTop={1}>
127→                <Text dimColor bold>
128→                  {group.category}
129→                </Text>
130→              </Box>
131→            )}
132→            {groupItems.map(({ session: s, idx }) => {
133→              if (idx < start || idx >= end) return null;
134→              const isSelected = idx === selectedIndex;
135→              const model = s.model ? shortModel(s.model) : "";
136→              const msgMaxLen = cols - 6;
137→
138→              return (
139→                <Box key={s.path} flexDirection="column">
140→                  {/* Line 1: message preview */}
141→                  <Box>
142→                    <Text color={isSelected ? colors.accent : colors.border}>
143→                      {isSelected ? `${IconSelected2} ` : "  "}
144→                    </Text>
145→                    {s.is_ongoing && (
146→                      <>
147→                        <OngoingDot />
148→                        <Text> </Text>
149→                      </>
150→                    )}
151→                    <Text
152→                      bold={isSelected}
153→                      color={isSelected ? colors.accent : colors.textPrimary}
154→                      backgroundColor={isSelected ? colors.pickerSelectedBg : undefined}
155→                    >
156→                      {truncate(s.first_message || s.session_id, msgMaxLen)}
157→                    </Text>
158→                  </Box>
159→                  {/* Line 2: metadata with Nerd Font icons — matches Go TUI */}
160→                  <Box>
161→                    <Text color={isSelected ? colors.accent : colors.border}>
162→                      {isSelected ? `${IconSelected2} ` : "  "}
163→                    </Text>
164→                    {model && <Text color={modelColor(s.model)}>{model.padEnd(10)}</Text>}
165→                    {s.git_branch ? (
166→                      <Text color={colors.gitBranch}>
167→                        {" "}
168→                        {IconBranch} {truncate(s.git_branch, 20)}
169→                      </Text>
170→                    ) : null}
171→                    <Text dimColor>
172→                      {" "}
173→                      {IconChat} {String(s.turn_count).padStart(3)}
174→                    </Text>
175→                    {s.total_tokens > 0 && (
176→                      <Text color={s.total_tokens > 150000 ? colors.tokenHigh : colors.textDim}>
177→                        {" "}
178→                        {IconToken} {formatTokens(s.total_tokens)}
179→                      </Text>
180→                    )}
181→                    {s.cost_usd > 0 && (
182→                      <Text color={colors.tokenHigh}> {formatCost(s.cost_usd)}</Text>
183→                    )}
184→                    <Text dimColor>
185→                      {" "}
186→                      {IconSession} {s.session_id.slice(0, 8)}
187→                    </Text>
188→                    <Text dimColor>
189→                      {" "}
190→                      {IconClock} {timeAgo(s.mod_time)}
191→                    </Text>
192→                  </Box>
193→                  {/* Thin separator — matches Go TUI's horizontal rule between cards.
194→                      Use truncate so it doesn't wrap if flex container is narrower than cols. */}
195→                  <Box paddingX={1}>
196→                    <Text color={colors.textMuted} wrap="truncate">
197→                      {IconHRule.repeat(200)}
198→                    </Text>
199→                  </Box>
200→                </Box>
201→              );
202→            })}
203→          </Box>
204→        );
205→      })}
206→
207→      {sessions.length === 0 && !loading && (
208→        <Box paddingX={1}>
209→          <Text dimColor>No sessions found</Text>
210→        </Box>
211→      )}
212→    </Box>
213→  );
214→}
