.project-tree__group-icon {
  display: inline-flex;
  align-items: center;
  vertical-align: middle;
  font-size: 13px;
  margin-right: 4px;
}

/* ---- Info Bar ---- */

.info-bar {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 6px 16px;
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  min-height: 36px;
  min-width: 0;
}

.info-bar__project {
  font-weight: 600;
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
}

.info-bar__session-id {
  color: var(--dim);
  font-size: 11px;
  font-family: var(--font-mono, monospace);
  opacity: 0.6;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
}

.info-bar__branch {
  color: var(--git-branch);
  font-size: 12px;
}

.info-bar__branch--dirty::after {
  content: " *";
  color: var(--context-warn);
}

.info-bar__pill {
  display: inline-flex;
  align-items: center;
  padding: 1px 8px;
  border-radius: 10px;
  font-size: 11px;
  font-weight: 600;
  color: #fff;
}

.info-bar__pill--bypass {
  background: var(--pill-bypass);
}

.info-bar__pill--acceptEdits {
  background: var(--pill-accept-edits);
}

.info-bar__pill--plan {
  background: var(--pill-plan);
}

.info-bar__pill--default {
  background: var(--text-muted);
}

.info-bar__context {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-left: auto;
  font-size: 11px;
  color: var(--text-dim);
  flex-shrink: 0;
}

.info-bar__context-bar {
  width: 60px;
  height: 6px;
  background: var(--bg);
  border-radius: 3px;
  overflow: hidden;
}

.info-bar__context-fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.3s ease;
}

.info-bar__tokens {
  color: var(--text-secondary);
  font-size: 12px;
  display: inline-flex;
  align-items: center;
  gap: 3px;
}

.info-bar__cost {
  color: var(--error);
  font-size: 12px;
  font-weight: 600;
  display: inline-flex;
  align-items: center;
  gap: 3px;
}

.info-bar__ongoing {
  display: flex;
  align-items: center;
  gap: 4px;
  color: var(--ongoing);
  font-size: 12px;
  animation: pulse 1.5s ease-in-out infinite;
}

@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

@keyframes spin {
  to {

